public class Program
{
    internal static void CleanupVaultsOnStartup() => LuxVault.CleanupVaults();
    internal static void CleanupVaultsOnShutdown() => LuxVault.CleanupVaults();

    private static SecureString Generate64BitSecureSeed()
    {
        byte[] seedBytes = new byte[8]; // 64 bits
        RandomNumberGenerator.Fill(seedBytes);

        var secure = new SecureString();
        // Zero-exposure: append bytes as chars without hex string conversion
        foreach (var b in seedBytes) secure.AppendChar((char)b);
        secure.MakeReadOnly();

        Array.Clear(seedBytes);
        return secure;
    }

    private static byte[] DeriveSessionKeyFromSecureSeed(SecureString secureSeed)
    {
        byte[] hashedKey = new byte[32]; // 256-bit session key
        IntPtr ptr = Marshal.SecureStringToGlobalAllocUnicode(secureSeed);
        try
        {
            unsafe {
                byte* pSeed = (byte*)ptr.ToPointer();
                // Extract original bytes from the Unicode chars
                byte[] seedBytes = new byte[secureSeed.Length];
                for (int i = 0; i < secureSeed.Length; i++) {
                    seedBytes[i] = (byte)pSeed[i * 2]; // Unicode is 2 bytes per char
                }

                MonocypherNative.crypto_blake2b(hashedKey, (nuint)hashedKey.Length, seedBytes, (nuint)seedBytes.Length);
                Array.Clear(seedBytes);
            }
        }
        finally
        {
            Marshal.ZeroFreeGlobalAllocUnicode(ptr);
        }
        return hashedKey;
    }

    public static async Task Main(string[] args)
    {
        // Apply OS-level hardening (Anti-Dumping)
        ProcessHardening.Apply();

        // 0. Cleanup vaults on startup
        CleanupVaultsOnStartup();

        // 1. Generate 64-bit seed and wrap in SecureString
        using SecureString secureSeed = Generate64BitSecureSeed();

        // 2. Derive the 256-bit session key
        byte[] sessionKey = DeriveSessionKeyFromSecureSeed(secureSeed);

        // 3. Initialize the global vault security with this transient key
        LuxVault.InitializeSessionKey(sessionKey);
        ProtectedSecret.InitializeSessionKey(sessionKey);

        var host = Host.CreateDefaultBuilder(args)
            .UseContentRoot(AppContext.BaseDirectory)
            .ConfigureAppConfiguration((hostingContext, config) =>
            {
                config.AddJsonFile("config.json", optional: false, reloadOnChange: true);
                config.AddEnvironmentVariables();
            })
            .ConfigureServices((hostContext, services) =>
            {
                var serverConfigSection = hostContext.Configuration.GetSection("Server");
                services.Configure<ServerConfig>(serverConfigSection);

                var serverConfig = new ServerConfig();
                serverConfigSection.Bind(serverConfig);

                services.AddSingleton(serverConfig);
                if (serverConfig.Rest != null) services.AddSingleton(serverConfig.Rest);
                if (serverConfig.Grpc != null) services.AddSingleton(serverConfig.Grpc);
                if (serverConfig.Mqtt != null) services.AddSingleton(serverConfig.Mqtt);
                if (serverConfig.Soap != null) services.AddSingleton(serverConfig.Soap);
                if (serverConfig.JsonRpc != null) services.AddSingleton(serverConfig.JsonRpc);
                if (serverConfig.Database != null) services.AddSingleton(serverConfig.Database);
                if (serverConfig.Ethereum != null) services.AddSingleton(serverConfig.Ethereum);
                if (serverConfig.Bitcoin != null) services.AddSingleton(serverConfig.Bitcoin);
                if (serverConfig.Solana != null) services.AddSingleton(serverConfig.Solana);
                if (serverConfig.Stellar != null) services.AddSingleton(serverConfig.Stellar);
                if (serverConfig.Cardano != null) services.AddSingleton(serverConfig.Cardano);
                if (serverConfig.Secret != null) services.AddSingleton(serverConfig.Secret);
                if (serverConfig.Aws != null) services.AddSingleton(serverConfig.Aws);
                if (serverConfig.Azure != null) services.AddSingleton(serverConfig.Azure);
                if (serverConfig.Gcp != null) services.AddSingleton(serverConfig.Gcp);
                if (serverConfig.Websocket != null) services.AddSingleton(serverConfig.Websocket);
                if (serverConfig.Emercoin != null) 
                {
                    services.AddSingleton(serverConfig.Emercoin);
                    services.Configure<EmercoinConfig>(hostContext.Configuration.GetSection("Server:Emercoin"));
                }
                services.AddSingleton<SrvBackend>();

                services.AddHttpClient();
                services.AddSingleton<IEmercoinNvsClient, EmercoinNvsClient>();
                services.AddSingleton<IEmercoinAuthService, EmercoinAuthService>();

                services.AddSingleton<IClusterManager, ClusterManager>();
                services.AddSingleton<ILuxVaultService, LuxVaultService>();
                services.AddSingleton<IParser, ConfigParser>();

                services.AddHttpClient();
                services.AddSingleton<IEmercoinNvsClient, EmercoinNvsClient>();
                services.AddSingleton<IEmercoinAuthService, EmercoinAuthService>();

                if (serverConfig.Database != null) services.AddSingleton<IProtocolBackend, DatabaseBackend>();
                if (serverConfig.Ethereum != null) services.AddSingleton<IProtocolBackend, EthereumBackend>();
                if (serverConfig.Bitcoin != null) services.AddSingleton<IProtocolBackend, BitcoinBackend>();
                if (serverConfig.Solana != null) services.AddSingleton<IProtocolBackend, SolanaBackend>();
                if (serverConfig.Stellar != null) services.AddSingleton<IProtocolBackend, StellarBackend>();
                if (serverConfig.Cardano != null) services.AddSingleton<IProtocolBackend, CardanoBackend>();
                if (serverConfig.Secret != null) services.AddSingleton<IProtocolBackend, SecretBackend>();
                if (serverConfig.Aws != null) services.AddSingleton<IProtocolBackend, AwsBackend>();
                if (serverConfig.Azure != null) services.AddSingleton<IProtocolBackend, AzureBackend>();
                if (serverConfig.Gcp != null) services.AddSingleton<IProtocolBackend, GcpBackend>();
                if (serverConfig.Websocket != null) services.AddSingleton<IProtocolBackend, WebsocketBackend>();
                if (serverConfig.JsonRpc != null) services.AddSingleton<IProtocolBackend, JsonRpcBackend>();
                if (serverConfig.Rest != null) services.AddSingleton<IProtocolBackend, RestBackend>();
                if (serverConfig.Soap != null) services.AddSingleton<IProtocolBackend, SoapBackend>();
                if (serverConfig.Grpc != null) services.AddSingleton<IProtocolBackend, GrpcBackend>();
                services.AddSingleton<IProtocolBackend, SrvBackend>();

                services.AddSingleton<INinePFSDispatcher, NinePFSDispatcher>();
                services.AddHostedService<NinePServer>();
            })
            .Build();

        Array.Clear(sessionKey);

        try {
            await host.RunAsync();
        }
        finally {
            // Cleanup vaults on shutdown
            CleanupVaultsOnShutdown();
        }
    }
}

using NinePSharp.Server.Utils;
using System;
using System.Buffers.Binary;
using System.Collections.Generic;
using System.Linq;
using System.Security;
using System.Threading.Tasks;
using Akka.Actor;
using NinePSharp.Messages;
using NinePSharp.Protocol;
using NinePSharp.Constants;
using NinePSharp.Server.Interfaces;
using NinePSharp.Server.Cluster;
using NinePSharp.Server.Cluster.Actors;

namespace NinePSharp.Server;

internal class RootFileSystem : INinePFileSystem
{
    private readonly List<IProtocolBackend> _backends;
    private readonly IClusterManager? _clusterManager;
    private readonly TimeSpan _clusterTimeout = TimeSpan.FromSeconds(3);
    private INinePFileSystem? _delegatedFs;

    public bool DotU { get; set; }

    public RootFileSystem(List<IProtocolBackend> backends, IClusterManager? clusterManager = null)
    {
        _backends = backends;
        _clusterManager = clusterManager;
    }

    public async Task<Rwalk> WalkAsync(Twalk twalk)
    {
        // If we are already delegating, pass the walk to the backend
        if (_delegatedFs != null) return await _delegatedFs.WalkAsync(twalk);

        if (twalk.Wname.Length == 0) return new Rwalk(twalk.Tag, Array.Empty<Qid>());

        // Try to find a backend that matches the first element of the walk
        var name = twalk.Wname[0];
        var backend = _backends.FirstOrDefault(b => b.MountPath.Trim('/') == name);

        if (backend == null && _clusterManager?.Registry != null)
        {
            var mountPath = "/" + name;
            var registryResponse = await _clusterManager.Registry.Ask<object>(new GetBackend(mountPath), _clusterTimeout);
            if (registryResponse is BackendFound found)
            {
                var sessionResponse = await found.Actor.Ask<object>(new SpawnSession(), _clusterTimeout);
                if (sessionResponse is SessionSpawned session)
                {
                    _delegatedFs = new RemoteFileSystem(session.Session) { DotU = DotU };

                    var qid = new Qid(QidType.QTDIR, 0, (ulong)name.GetHashCode());
                    var qids = new List<Qid> { qid };

                    if (twalk.Wname.Length > 1)
                    {
                        var subWalk = new Twalk(twalk.Tag, twalk.Fid, twalk.NewFid, twalk.Wname.Skip(1).ToArray());
                        var subResponse = await _delegatedFs.WalkAsync(subWalk);
                        if (subResponse.Wqid != null)
                        {
                            qids.AddRange(subResponse.Wqid);
                        }
                    }

                    return new Rwalk(twalk.Tag, qids.ToArray());
                }
            }
        }

        if (backend != null)
        {
            // Enter the backend
            _delegatedFs = backend.GetFileSystem(null);
            _delegatedFs.DotU = this.DotU;

            var qid = new Qid(QidType.QTDIR, 0, (ulong)name.GetHashCode());
            var qids = new List<Qid> { qid };

            if (twalk.Wname.Length > 1)
            {
                // We have more steps! 
                // We must create a TWALK that starts from the backend root.
                // NOTE: the FID in twalk is the root fid, but the sub-walk
                // is conceptually walking relative to the new delegated FS.
                var subWalk = new Twalk(twalk.Tag, twalk.Fid, twalk.NewFid, twalk.Wname.Skip(1).ToArray());
                var subResponse = await _delegatedFs.WalkAsync(subWalk);

                if (subResponse.Wqid != null)
                {
                    qids.AddRange(subResponse.Wqid);
                }
            }

            return new Rwalk(twalk.Tag, qids.ToArray());
        }

        return new Rwalk(twalk.Tag, null); 
    }

    public async Task<Rread> ReadAsync(Tread tread)
    {
        if (_delegatedFs != null) return await _delegatedFs.ReadAsync(tread);

        var mountNames = new HashSet<string>(StringComparer.Ordinal);

        foreach (var backend in _backends)
        {
            var name = backend.MountPath.Trim('/');
            if (string.IsNullOrEmpty(name)) continue;
            mountNames.Add(name);
        }

        if (_clusterManager?.Registry != null)
        {
            try
            {
                var response = await _clusterManager.Registry.Ask<object>(new GetBackends(), _clusterTimeout);
                if (response is BackendsSnapshot snapshot)
                {
                    foreach (var mountPath in snapshot.MountPaths)
                    {
                        var name = mountPath.Trim('/');
                        if (string.IsNullOrEmpty(name)) continue;
                        mountNames.Add(name);
                    }
                }
            }
            catch
            {
                // Best-effort federation listing; root should still serve local mounts.
            }
        }

        var entries = new List<byte>();
        foreach (var name in mountNames.OrderBy(n => n, StringComparer.Ordinal))
        {
            var stat = new Stat(0, 0, 0, new Qid(QidType.QTDIR, 0, (ulong)name.GetHashCode()), 0755 | (uint)NinePConstants.FileMode9P.DMDIR, 0, 0, 0, name, "scott", "scott", "scott", dotu: DotU);

            var entryBuffer = new byte[stat.Size];
            int offset = 0;
            stat.WriteTo(entryBuffer, ref offset);
            entries.AddRange(entryBuffer);
        }

        var allData = entries.ToArray();
        if (tread.Offset >= (ulong)allData.Length) return new Rread(tread.Tag, Array.Empty<byte>());

        int totalToSend = 0;
        int currentOffset = (int)tread.Offset;
        while (currentOffset + 2 <= allData.Length)
        {
            int entrySize = BinaryPrimitives.ReadUInt16LittleEndian(allData.AsSpan(currentOffset, 2)) + 2;
            if (entrySize <= 0 || currentOffset + entrySize > allData.Length) break;
            if (totalToSend + entrySize > tread.Count) break;
            totalToSend += entrySize;
            currentOffset += entrySize;
        }

        if (totalToSend == 0) return new Rread(tread.Tag, Array.Empty<byte>());
        return new Rread(tread.Tag, allData.AsMemory((int)tread.Offset, totalToSend).ToArray());
    }

    public async Task<Rstat> StatAsync(Tstat tstat)
    {
        if (_delegatedFs != null) return await _delegatedFs.StatAsync(tstat);
        var stat = new Stat(0, 0, 0, new Qid(QidType.QTDIR, 0, 0), 0755 | (uint)NinePConstants.FileMode9P.DMDIR, 0, 0, 0, "/", "scott", "scott", "scott", dotu: DotU);
        return new Rstat(tstat.Tag, stat);
    }

    public Task<Rclunk> ClunkAsync(Tclunk tclunk) => _delegatedFs?.ClunkAsync(tclunk) ?? Task.FromResult(new Rclunk(tclunk.Tag));

    public async Task<Ropen> OpenAsync(Topen topen)
    {
        if (_delegatedFs != null) return await _delegatedFs.OpenAsync(topen);
        return new Ropen(topen.Tag, new Qid(QidType.QTDIR, 0, 0), 0);
    }

    public Task<Rwrite> WriteAsync(Twrite twrite) => _delegatedFs?.WriteAsync(twrite) ?? throw new NinePNotSupportedException();
    public Task<Rwstat> WstatAsync(Twstat twstat) => _delegatedFs?.WstatAsync(twstat) ?? throw new NinePNotSupportedException();
    public Task<Rremove> RemoveAsync(Tremove tremove) => _delegatedFs?.RemoveAsync(tremove) ?? throw new NinePNotSupportedException();

    public Task<Rgetattr> GetAttrAsync(Tgetattr tgetattr)
    {
        if (_delegatedFs != null) return _delegatedFs.GetAttrAsync(tgetattr);

        var qid = new Qid(QidType.QTDIR, 0, 0);
        ulong now = (ulong)DateTimeOffset.UtcNow.ToUnixTimeSeconds();
        return Task.FromResult(new NinePSharp.Messages.Rgetattr(tgetattr.Tag, (ulong)NinePConstants.GetAttrMask.P9_GETATTR_BASIC, qid, (uint)NinePConstants.FileMode9P.DMDIR | 0x1EDu, 0, 0, 1, 0, 0, 4096, 0, now, 0, now, 0, now, 0, 0, 0, 0, 0));
    }

    public Task<Rsetattr> SetAttrAsync(Tsetattr tsetattr) => _delegatedFs?.SetAttrAsync(tsetattr) ?? throw new NinePNotSupportedException();

    public Task<Rstatfs> StatfsAsync(Tstatfs tstatfs)
    {
        if (_delegatedFs != null) return _delegatedFs.StatfsAsync(tstatfs);

        // Return dummy file system statistics for the root.
        // Block size 4096, 1,000,000 blocks total, 500,000 free.
        return Task.FromResult(new NinePSharp.Messages.Rstatfs(tstatfs.Tag, 0x01021997, 4096, 1000000, 500000, 500000, 1000, 500, 0, 256));
    }

    public async Task<Rreaddir> ReaddirAsync(Treaddir treaddir)
    {
        if (_delegatedFs != null) return await _delegatedFs.ReaddirAsync(treaddir);

        var mountNames = new HashSet<string>(StringComparer.Ordinal);

        foreach (var backend in _backends)
        {
            var name = backend.MountPath.Trim('/');
            if (string.IsNullOrEmpty(name)) continue;
            mountNames.Add(name);
        }

        if (_clusterManager?.Registry != null)
        {
            try
            {
                var response = await _clusterManager.Registry.Ask<object>(new GetBackends(), _clusterTimeout);
                if (response is BackendsSnapshot snapshot)
                {
                    foreach (var mountPath in snapshot.MountPaths)
                    {
                        var name = mountPath.Trim('/');
                        if (string.IsNullOrEmpty(name)) continue;
                        mountNames.Add(name);
                    }
                }
            }
            catch
            {
                // Best-effort federation listing; root should still serve local mounts.
            }
        }

        var entries = new List<byte>();
        ulong currentCountOffset = 0;

        foreach (var name in mountNames.OrderBy(n => n, StringComparer.Ordinal))
        {
            currentCountOffset++;
            // 9P2000.L Readdir returns [qid[13] offset[8] type[1] name[s]]
            var qid = new Qid(QidType.QTDIR, 0, (ulong)name.GetHashCode());

            // Calculate size: qid(13) + offset(8) + type(1) + name string (2 + len)
            int nameLen = System.Text.Encoding.UTF8.GetByteCount(name);
            int entrySize = 13 + 8 + 1 + 2 + nameLen;
            var entryBuffer = new byte[entrySize];

            int writeOffset = 0;
            // Write Qid
            entryBuffer[writeOffset++] = (byte)qid.Type;
            BinaryPrimitives.WriteUInt32LittleEndian(entryBuffer.AsSpan(writeOffset, 4), qid.Version); writeOffset += 4;
            BinaryPrimitives.WriteUInt64LittleEndian(entryBuffer.AsSpan(writeOffset, 8), qid.Path); writeOffset += 8;

            // Write Offset (the offset for the NEXT read to start at)
            BinaryPrimitives.WriteUInt64LittleEndian(entryBuffer.AsSpan(writeOffset, 8), currentCountOffset); writeOffset += 8;

            // Write Type
            entryBuffer[writeOffset++] = (byte)qid.Type;

            // Write Name
            BinaryPrimitives.WriteUInt16LittleEndian(entryBuffer.AsSpan(writeOffset, 2), (ushort)nameLen); writeOffset += 2;
            System.Text.Encoding.UTF8.GetBytes(name).CopyTo(entryBuffer.AsSpan(writeOffset, nameLen));
            writeOffset += nameLen;

            entries.AddRange(entryBuffer);
        }

        var allData = entries.ToArray();

        // Note: 9P2000.L Readdir uses an abstract 'offset'. Our offset happens to be identical to the array index of the entries list.
        // We will just return the block of entries starting from the requested offset index.
        // For simplicity in this dummy root FS, if offset > 0, we'll try to slice chunks.

        if (treaddir.Offset == 0)
        {
             var chunk = allData.AsSpan(0, (int)Math.Min((long)treaddir.Count, (long)allData.Length)).ToArray();
             return new Rreaddir((uint)(chunk.Length + NinePConstants.HeaderSize + 4), treaddir.Tag, (uint)chunk.Length, chunk);
        }
        else
        {
            // If offset > 0, we'd need to parse our generated list to find the element.
            // Since Root FS is so small, we can re-generate it every time, but here we just return empty for subsequent reads for simplicity,
            // assuming the first read (offset 0) fetched all mounts (they fit in a standard 8k buffer easily).
            return new Rreaddir(NinePConstants.HeaderSize + 4, treaddir.Tag, 0, Array.Empty<byte>());
        }
    }
    public INinePFileSystem Clone()
    {
        var clone = new RootFileSystem(_backends, _clusterManager) { DotU = this.DotU };
        if (_delegatedFs != null) clone._delegatedFs = _delegatedFs.Clone();
        return clone;
    }
}

using System;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using NinePSharp.Server.Interfaces;

namespace NinePSharp.Server.Utils;

public class EmercoinAuthService : IEmercoinAuthService
{
    private readonly IEmercoinNvsClient _nvsClient;
    private readonly ILogger<EmercoinAuthService> _logger;

    public EmercoinAuthService(IEmercoinNvsClient nvsClient, ILogger<EmercoinAuthService> logger)
    {
        _nvsClient = nvsClient;
        _logger = logger;
    }

    public async Task<bool> IsCertificateAuthorizedAsync(X509Certificate2 certificate)
    {
        if (certificate == null) return false;

        // Extract the thumbprint or serial number - Emercoin NVS records for SSL 
        // usually use the name "ssl:<serial_number_or_thumbprint>"
        string thumbprint = certificate.Thumbprint.ToLowerInvariant();
        string serialNumber = certificate.SerialNumber.ToLowerInvariant();

        _logger.LogInformation("Verifying certificate in Emercoin NVS. Thumbprint: {Thumbprint}, Serial: {Serial}", thumbprint, serialNumber);

        // Check thumbprint record
        var record = await _nvsClient.GetNameValueAsync($"ssl:{thumbprint}");
        if (record != null)
        {
            _logger.LogInformation("Authorized via Emercoin NVS (thumbprint match).");
            return true;
        }

        // Check serial number record
        record = await _nvsClient.GetNameValueAsync($"ssl:{serialNumber}");
        if (record != null)
        {
            _logger.LogInformation("Authorized via Emercoin NVS (serial match).");
            return true;
        }

        _logger.LogWarning("Certificate NOT found in Emercoin NVS.");
        return false;
    }
}

using System;
using System.Net.Http;
using System.Net.Http.Headers;
using System.Text;
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace NinePSharp.Server.Utils;

public record EmercoinConfig
{
    public string EndpointUrl { get; set; } = "http://127.0.0.1:6662/";
    public string Username { get; set; } = "";
    public string Password { get; set; } = "";
}

public interface IEmercoinNvsClient
{
    Task<string?> GetNameValueAsync(string name);
}

public class EmercoinNvsClient : IEmercoinNvsClient
{
    private readonly HttpClient _httpClient;
    private readonly EmercoinConfig _config;
    private readonly ILogger<EmercoinNvsClient> _logger;

    public EmercoinNvsClient(HttpClient httpClient, IOptions<EmercoinConfig> config, ILogger<EmercoinNvsClient> logger)
    {
        _httpClient = httpClient;
        _config = config.Value;
        _logger = logger;

        if (!string.IsNullOrEmpty(_config.Username))
        {
            var authString = Convert.ToBase64String(Encoding.ASCII.GetBytes($"{_config.Username}:{_config.Password}"));
            _httpClient.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Basic", authString);
        }
    }

    public async Task<string?> GetNameValueAsync(string name)
    {
        try
        {
            var request = new
            {
                jsonrpc = "1.0",
                id = "ninepsharp",
                method = "name_show",
                @params = new[] { name }
            };

            var content = new StringContent(JsonSerializer.Serialize(request), Encoding.UTF8, "application/json");
            var response = await _httpClient.PostAsync(_config.EndpointUrl, content);

            if (!response.IsSuccessStatusCode) return null;

            using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
            if (doc.RootElement.TryGetProperty("result", out var result) && result.ValueKind != JsonValueKind.Null)
            {
                return result.GetProperty("value").GetString();
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to fetch name {Name} from Emercoin", name);
        }

        return null;
    }
}

using System;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using System.Runtime.Versioning;
using System.Security;
using System.Security.Cryptography;
using System.Text;
using System.Threading;
using System.Threading.Tasks;

[assembly: InternalsVisibleTo("NinePSharp.Tests")]

namespace NinePSharp.Server.Utils
{
    /// <summary>
    /// Provides zero-exposure secret management using Monocypher (XChaCha20-Poly1305) 
    /// and sharded RAM-locked pinned memory for high-performance parallel execution.
    /// </summary>
    public static class LuxVault
    {
        public static readonly string VaultDirectory = Path.Combine(AppContext.BaseDirectory, "vaults");
        private const int KeySize = 32;
        private const int NonceSize = 24; 
        private const int MacSize = 16;
        private const int SaltSize = 16;

        // ─── Parallel Optimization & Sharded Arenas ─────────────────────────

        private static readonly int MaxParallelOps = (int)Math.Max(1, Environment.ProcessorCount * 0.8);
        private static readonly SemaphoreSlim ConcurrencyGovernor = new(MaxParallelOps, MaxParallelOps);
        private static int _concurrencyGovernorEnabled = 1;

        internal static bool IsConcurrencyGovernorEnabled => Volatile.Read(ref _concurrencyGovernorEnabled) == 1;
        internal static void SetConcurrencyGovernorEnabled(bool enabled) => Volatile.Write(ref _concurrencyGovernorEnabled, enabled ? 1 : 0);

        private static readonly ICpuMonitor? CpuMonitor;
        private static readonly Timer? CpuMonitorTimer;
        private static int _currentLimit = MaxParallelOps;
        private static DateTime _lastAdjustment = DateTime.MinValue;

        static LuxVault()
        {
            // Select platform-appropriate monitor
            if (OperatingSystem.IsWindows())
            {
                CpuMonitor = new WindowsCpuMonitor();
            }
            else if (OperatingSystem.IsLinux())
            {
                CpuMonitor = new LinuxCpuMonitor();
            }

            if (CpuMonitor != null)
            {
                // Start adaptive CPU monitoring - checks every 2 seconds
                CpuMonitorTimer = new Timer(_ => AdjustConcurrencyBasedOnCpu(), null,
                    TimeSpan.FromSeconds(2), TimeSpan.FromSeconds(2));
            }
        }

        private static void AdjustConcurrencyBasedOnCpu()
        {
            if (CpuMonitor == null) return;

            // Rate limit adjustments to once per 5 seconds
            if ((DateTime.UtcNow - _lastAdjustment).TotalSeconds < 5) return;

            try
            {
                float currentCpu = CpuMonitor.GetUsage();
                int targetLimit = _currentLimit;

                // If system CPU > 80%, reduce our concurrency
                if (currentCpu > 80f)
                {
                    targetLimit = Math.Max(1, _currentLimit - 1);
                }
                // If system CPU < 60%, we can increase (up to MaxParallelOps)
                else if (currentCpu < 60f && _currentLimit < MaxParallelOps)
                {
                    targetLimit = Math.Min(MaxParallelOps, _currentLimit + 1);
                }

                if (targetLimit != _currentLimit)
                {
                    // Adjust semaphore by releasing or waiting
                    int delta = targetLimit - _currentLimit;
                    if (delta > 0)
                    {
                        ConcurrencyGovernor.Release(delta);
                    }
                    else if (delta < 0)
                    {
                        for (int i = 0; i < Math.Abs(delta); i++)
                        {
                            ConcurrencyGovernor.Wait(0); 
                        }
                    }

                    _currentLimit = targetLimit;
                    _lastAdjustment = DateTime.UtcNow;
                }
            }
            catch { /* Monitoring should never crash the vault */ }
        }

        private interface ICpuMonitor { float GetUsage(); }

        [SupportedOSPlatform("windows")]
        private class WindowsCpuMonitor : ICpuMonitor
        {
            private readonly PerformanceCounter? _counter;
            public WindowsCpuMonitor()
            {
                try {
                    _counter = new PerformanceCounter("Processor", "% Processor Time", "_Total");
                    _counter.NextValue();
                } catch { _counter = null; }
            }
            public float GetUsage() => _counter?.NextValue() ?? 0f;
        }

        private class LinuxCpuMonitor : ICpuMonitor
        {
            public float GetUsage()
            {
                try {
                    // Use loadavg as a proxy for CPU usage on Linux
                    // Format: "0.10 0.05 0.01 1/123 12345"
                    string loadStr = File.ReadAllText("/proc/loadavg").Split(' ')[0];
                    float load = float.Parse(loadStr);
                    // Convert load to a percentage based on core count
                    return (load / Environment.ProcessorCount) * 100f;
                } catch { return 0f; }
            }
        }

        public static readonly SecureMemoryArena[] Arenas = Enumerable.Range(0, MaxParallelOps)
            .Select(_ => new SecureMemoryArena(1024 * 1024)) // 1MB per shard
            .ToArray();

        /// <summary>
        /// Selects an arena shard based on the current thread ID to ensure lock-free scaling.
        /// </summary>
        internal static SecureMemoryArena GetLocalArena()
        {
            int index = Math.Abs(Thread.CurrentThread.ManagedThreadId) % Arenas.Length;
            return Arenas[index];
        }

        private static ConcurrencyGovernorGuard AcquireConcurrencyGovernor()
        {
            var governor = Volatile.Read(ref _concurrencyGovernorEnabled) == 1 ? ConcurrencyGovernor : null;
            return new ConcurrencyGovernorGuard(governor);
        }

        private readonly struct ConcurrencyGovernorGuard : IDisposable
        {
            private readonly SemaphoreSlim? _governor;

            public ConcurrencyGovernorGuard(SemaphoreSlim? governor)
            {
                _governor = governor;
                _governor?.Wait();
            }

            public void Dispose()
            {
                _governor?.Release();
            }
        }

        // ────────────────────────────────────────────────────────────────────

        internal static int Iterations = 600000;
        private static byte[]? _sessionKey;
        private static readonly object SessionKeyInitLock = new();

        public static void InitializeSessionKey(ReadOnlySpan<byte> sessionKey)
        {
            if (Volatile.Read(ref _sessionKey) != null) return;

            lock (SessionKeyInitLock)
            {
                if (_sessionKey != null) return;

                var pinnedKey = GC.AllocateArray<byte>(sessionKey.Length, pinned: true);
                sessionKey.CopyTo(pinnedKey);
                unsafe {
                    fixed (byte* pKey = pinnedKey) {
                        MemoryLock.Lock((IntPtr)pKey, (nuint)pinnedKey.Length);
                    }
                }
                Volatile.Write(ref _sessionKey, pinnedKey);
            }
        }

        public static string GetVaultPath(string filename)
        {
            Directory.CreateDirectory(VaultDirectory);
            return Path.Combine(VaultDirectory, filename);
        }

        public static void CleanupVaults()
        {
            if (Directory.Exists(VaultDirectory))
            {
                try { Directory.Delete(VaultDirectory, true); } catch { /* Ignore */ }
            }
            try { Directory.CreateDirectory(VaultDirectory); } catch { /* Ignore */ }
        }

        public static string GenerateHiddenId(ReadOnlySpan<byte> seed)
        {
            if (seed.Length != 32) throw new ArgumentException("Seed must be exactly 32 bytes.");

            using var gate = AcquireConcurrencyGovernor();

            var arena = GetLocalArena();
            using var hidden = new SecureBuffer(32, arena);
            using var secretKey = new SecureBuffer(32, arena);
            Span<byte> seedCopy = stackalloc byte[32];
            seed.CopyTo(seedCopy);

            unsafe
            {
                fixed (byte* pSeed = seedCopy, pHidden = hidden.Span, pSecret = secretKey.Span)
                {
                    MonocypherNative.crypto_elligator_key_pair(pHidden, pSecret, pSeed);
                }
            }

            return Convert.ToHexString(hidden.Span).ToLowerInvariant();
        }

        private delegate T ReadOnlySpanAction<T>(ReadOnlySpan<byte> span);

        private static T WithSecureString<T>(SecureString secureString, ReadOnlySpanAction<T> action)
        {
            IntPtr ptr = Marshal.SecureStringToGlobalAllocUnicode(secureString);
            nuint unmanagedLen = (nuint)(secureString.Length * 2);
            MemoryLock.Lock(ptr, unmanagedLen);

            try
            {
                unsafe {
                    int length = secureString.Length;
                    char* chars = (char*)ptr.ToPointer();
                    int byteCount = Encoding.UTF8.GetByteCount(chars, length);
                    if (byteCount == 0) return action(ReadOnlySpan<byte>.Empty);

                    using (var secureBuffer = new SecureBuffer(byteCount, GetLocalArena()))
                    {
                        fixed (byte* pBytes = secureBuffer.Span)
                        {
                            Encoding.UTF8.GetBytes(chars, length, pBytes, byteCount);
                        }
                        return action(secureBuffer.Span);
                    }
                }
            }
            finally
            {
                MemoryLock.Unlock(ptr, unmanagedLen);
                Marshal.ZeroFreeGlobalAllocUnicode(ptr);
            }
        }

        private static void MixSessionKey(ReadOnlySpan<byte> input, Span<byte> output)
        {
            var sessionKey = Volatile.Read(ref _sessionKey);
            if (sessionKey == null)
            {
                input.CopyTo(output);
                return;
            }

            using (var buffer = new SecureBuffer(input.Length + sessionKey.Length, GetLocalArena()))
            {
                input.CopyTo(buffer.Span);
                sessionKey.CopyTo(buffer.Span.Slice(input.Length));
                unsafe {
                    fixed (byte* pMixed = output, pBuffer = buffer.Span) {
                        MonocypherNative.crypto_blake2b_ptr(pMixed, (nuint)output.Length, pBuffer, (nuint)buffer.Length);
                    }
                }
            }
        }

        public static void DeriveSeed(string password, ReadOnlySpan<byte> nonce, Span<byte> output)
        {
            if (password == null) throw new ArgumentNullException(nameof(password));
            if (nonce.Length < 8) throw new ArgumentException("Nonce must be at least 8 bytes.");

            using (var rawSeed = new SecureBuffer(KeySize, GetLocalArena()))
            {
                Rfc2898DeriveBytes.Pbkdf2(password, nonce, rawSeed.Span, Iterations, HashAlgorithmName.SHA256);
                MixSessionKey(rawSeed.Span, output);
            }
        }

        public static unsafe void DeriveSeed(SecureString password, ReadOnlySpan<byte> nonce, Span<byte> output)
        {
            if (nonce.Length < 8) throw new ArgumentException("Nonce must be at least 8 bytes.");

            byte[] localNonce = nonce.ToArray();
            fixed (byte* pOutput = output)
            {
                byte* pOutputLocal = pOutput;
                WithSecureString(password, bytes => {
                    using (var rawSeed = new SecureBuffer(KeySize, GetLocalArena()))
                    {
                        Rfc2898DeriveBytes.Pbkdf2(bytes, localNonce, rawSeed.Span, Iterations, HashAlgorithmName.SHA256);
                        MixSessionKey(rawSeed.Span, new Span<byte>(pOutputLocal, KeySize));
                        return true;
                    }
                });
            }
        }

        public static void DeriveSeed(ReadOnlySpan<byte> passwordBytes, ReadOnlySpan<byte> nonce, Span<byte> output)
        {
            if (nonce.Length < 8) throw new ArgumentException("Nonce must be at least 8 bytes.");

            using (var rawSeed = new SecureBuffer(KeySize, GetLocalArena()))
            {
                Rfc2898DeriveBytes.Pbkdf2(passwordBytes, nonce, rawSeed.Span, Iterations, HashAlgorithmName.SHA256);
                MixSessionKey(rawSeed.Span, output);
            }
        }

        public static byte[] Encrypt(ReadOnlySpan<byte> plaintext, string password)
        {
            if (password == null) throw new ArgumentNullException(nameof(password));
            using var gate = AcquireConcurrencyGovernor();

            Span<byte> salt = stackalloc byte[SaltSize];
            RandomNumberGenerator.Fill(salt);
            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(password, salt, key.Span);
                return EncryptInternal(plaintext, key.Span, salt);
            }
        }

        public static byte[] Encrypt(ReadOnlySpan<byte> plaintext, SecureString password)
        {
            if (password == null) throw new ArgumentNullException(nameof(password));
            using var gate = AcquireConcurrencyGovernor();

            Span<byte> salt = stackalloc byte[SaltSize];
            RandomNumberGenerator.Fill(salt);
            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(password, salt, key.Span);
                return EncryptInternal(plaintext, key.Span, salt);
            }
        }

        public static byte[] Encrypt(ReadOnlySpan<byte> plaintext, ReadOnlySpan<byte> keyMaterial)
        {
            using var gate = AcquireConcurrencyGovernor();

            Span<byte> salt = stackalloc byte[SaltSize];
            RandomNumberGenerator.Fill(salt);
            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(keyMaterial, salt, key.Span);
                return EncryptInternal(plaintext, key.Span, salt);
            }
        }

        private static byte[] EncryptInternal(ReadOnlySpan<byte> plaintext, ReadOnlySpan<byte> key, ReadOnlySpan<byte> salt)
        {
            byte[] finalPayload = new byte[SaltSize + NonceSize + MacSize + plaintext.Length];
            salt.CopyTo(finalPayload.AsSpan(0, SaltSize));

            using var nonce = new SecureBuffer(NonceSize, GetLocalArena());
            RandomNumberGenerator.Fill(nonce.Span);
            nonce.Span.CopyTo(finalPayload.AsSpan(SaltSize, NonceSize));

            using var mac = new SecureBuffer(MacSize, GetLocalArena());

            unsafe {
                fixed (byte* pPayload = finalPayload, pMac = mac.Span, pKey = key, pNonce = nonce.Span, pPlain = plaintext) 
                {
                    byte* pCipher = pPayload + SaltSize + NonceSize + MacSize;
                    MonocypherNative.crypto_aead_lock(pCipher, pMac, pKey, pNonce, null, 0, pPlain, (nuint)plaintext.Length);
                }
            }

            mac.Span.CopyTo(finalPayload.AsSpan(SaltSize + NonceSize, MacSize));
            return finalPayload;
        }

        public static SecureSecret? DecryptToBytes(byte[] payload, string password)
        {
            if (payload == null || payload.Length < SaltSize + NonceSize + MacSize) return null;
            using var gate = AcquireConcurrencyGovernor();

            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(password, payload.AsSpan(0, SaltSize), key.Span);
                return DecryptInternal(payload, key.Span);
            }
        }

        public static SecureSecret? DecryptToBytes(byte[] payload, SecureString password)
        {
            if (payload == null || payload.Length < SaltSize + NonceSize + MacSize) return null;
            using var gate = AcquireConcurrencyGovernor();

            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(password, payload.AsSpan(0, SaltSize), key.Span);
                return DecryptInternal(payload, key.Span);
            }
        }

        public static SecureSecret? DecryptToBytes(byte[] payload, ReadOnlySpan<byte> keyMaterial)
        {
            if (payload == null || payload.Length < SaltSize + NonceSize + MacSize) return null;
            using var gate = AcquireConcurrencyGovernor();

            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(keyMaterial, payload.AsSpan(0, SaltSize), key.Span);
                return DecryptInternal(payload, key.Span);
            }
        }

        public static SecureSecret? DecryptToBytesWithPasswordBytes(byte[] payload, ReadOnlySpan<byte> passwordBytes)
        {
            if (payload == null || payload.Length < SaltSize + NonceSize + MacSize) return null;
            using var gate = AcquireConcurrencyGovernor();

            using (var key = new SecureBuffer(KeySize, GetLocalArena()))
            {
                DeriveSeed(passwordBytes, payload.AsSpan(0, SaltSize), key.Span);
                return DecryptInternal(payload, key.Span);
            }
        }

        public static void StoreSecret(string name, byte[] plaintext, SecureString password)
        {
            var encrypted = Encrypt(plaintext, password);
            using var seed = new SecureBuffer(KeySize, GetLocalArena());
            DeriveSeed(password, Encoding.UTF8.GetBytes(name), seed.Span);
            var hiddenId = GenerateHiddenId(seed.Span);
            var path = GetVaultPath($"secret_{hiddenId}.vlt");
            File.WriteAllBytes(path, encrypted);
        }

        public static SecureSecret? LoadSecret(string name, SecureString password)
        {
            using var seed = new SecureBuffer(KeySize, GetLocalArena());
            DeriveSeed(password, Encoding.UTF8.GetBytes(name), seed.Span);
            try
            {
                var hiddenId = GenerateHiddenId(seed.Span);
                var path = GetVaultPath($"secret_{hiddenId}.vlt");
                if (!File.Exists(path)) return null;

                var encrypted = File.ReadAllBytes(path);
                return DecryptToBytes(encrypted, password);
            }
            finally
            {
            }
        }

        public static SecureSecret? LoadSecret(string name, ReadOnlySpan<byte> passwordBytes)
        {
            byte[] nameBytes = Encoding.UTF8.GetBytes(name);
            using var seed = new SecureBuffer(KeySize, GetLocalArena());
            DeriveSeed(passwordBytes, nameBytes, seed.Span);
            try
            {
                var hiddenId = GenerateHiddenId(seed.Span);
                var path = GetVaultPath($"secret_{hiddenId}.vlt");
                if (!File.Exists(path)) return null;

                var encrypted = File.ReadAllBytes(path);
                return DecryptToBytesWithPasswordBytes(encrypted, passwordBytes);
            }
            finally
            {
                Array.Clear(nameBytes);
            }
        }

        private static SecureSecret? DecryptInternal(byte[] payload, ReadOnlySpan<byte> key)
        {
            try
            {
                var arena = GetLocalArena();
                using var nonce = new SecureBuffer(NonceSize, arena);
                payload.AsSpan(SaltSize, NonceSize).CopyTo(nonce.Span);

                using var mac = new SecureBuffer(MacSize, arena);
                payload.AsSpan(SaltSize + NonceSize, MacSize).CopyTo(mac.Span);

                int ciphertextLen = payload.Length - (SaltSize + NonceSize + MacSize);
                using (var plaintextBuffer = new SecureBuffer(ciphertextLen, arena))
                {
                    int result;
                    unsafe {
                        fixed (byte* pPayload = payload, pKey = key) {
                            byte* pCiphertext = pPayload + SaltSize + NonceSize + MacSize;
                            fixed (byte* pPlain = plaintextBuffer.Span, pMac = mac.Span, pNonce = nonce.Span) {
                                result = MonocypherNative.crypto_aead_unlock(pPlain, pMac, pKey, pNonce, null, 0, pCiphertext, (nuint)ciphertextLen);
                            }
                        }
                    }
                    if (result == 0)
                    {
                        byte[] resultBytes = GC.AllocateArray<byte>(plaintextBuffer.Length, pinned: true);
                        plaintextBuffer.Span.CopyTo(resultBytes);
                        unsafe {
                            fixed (byte* pResult = resultBytes) {
                                MemoryLock.Lock((IntPtr)pResult, (nuint)resultBytes.Length);
                            }
                        }
                        return new SecureSecret(resultBytes);
                    }
                }
                return null;
            }
            catch (Exception ex) { throw new Exception("DECRYPT TO BYTES FAILED", ex); }
        }

        [Obsolete("Use DecryptToBytes to avoid leaking secrets into the managed string pool.")]
        public static string? Decrypt(byte[] payload, string password)
        {
            using var secret = DecryptToBytes(payload, password);
            return secret == null ? null : Encoding.UTF8.GetString(secret.Span);
        }

        [Obsolete("Use DecryptToBytes to avoid leaking secrets into the managed string pool.")]
        public static string? Decrypt(byte[] payload, SecureString password)
        {
            using var secret = DecryptToBytes(payload, password);
            return secret == null ? null : Encoding.UTF8.GetString(secret.Span);
        }

        [Obsolete("Use DecryptToBytes to avoid leaking secrets into the managed string pool.")]
        public static string? Decrypt(byte[] payload, ReadOnlySpan<byte> keyMaterial)
        {
            using var secret = DecryptToBytes(payload, keyMaterial);
            return secret == null ? null : Encoding.UTF8.GetString(secret.Span);
        }

        public static string ProtectConfig(string plainText, ReadOnlySpan<byte> masterKey)
        {
            var ciphertext = Encrypt(Encoding.UTF8.GetBytes(plainText), masterKey);
            return "secret://" + Convert.ToBase64String(ciphertext);
        }

        public static string? UnprotectConfig(string secretUri, ReadOnlySpan<byte> masterKey)
        {
            if (!secretUri.StartsWith("secret://")) return secretUri;
            var base64 = secretUri.Substring("secret://".Length);
            var ciphertext = Convert.FromBase64String(base64);
            using var secret = DecryptToBytes(ciphertext, masterKey);
            return secret == null ? null : Encoding.UTF8.GetString(secret.Span);
        }
    }
}

