            var logger = new Mock<ILogger>();
            var config = ClusterConfigLoader.LoadFromTextFile(path, logger.Object);

            Assert.Equal("NinePCluster", config.SystemName);
            Assert.Equal("127.0.0.1", config.Hostname);
