using FsCheck.Xunit;
using NinePSharp.Backends.Pipes;
using NinePSharp.Backends.PowerShell;
using NinePSharp.Messages;
using NinePSharp.Server.Interfaces;
using NinePSharp.Server.Utils;
using Xunit;
using Xunit.Abstractions;

namespace NinePSharp.Tests
{
    public class GridRobustnessTests
    {
        private readonly ITestOutputHelper _output;

        public GridRobustnessTests(ITestOutputHelper output)
        {
            _output = output;
        }

        #region LuxVault Security Fuzzing

        [Property(MaxTest = 100, DisplayName = "LuxVault: Decrypt should always return null for corrupted ciphertexts")]
        public bool LuxVault_MAC_Corruption_Fuzz_Property(byte[] plaintext, string password)
        {
            if (plaintext == null || password == null) return true;

            // 1. Encrypt validly
            byte[] ciphertext = LuxVault.Encrypt(plaintext, password);
            if (ciphertext.Length < 32) return true; // Skip too small

            // 2. Corrupt exactly one random byte in the MAC or Ciphertext region
            // (Salt is first 16 bytes, Nonce is next 24, MAC is next 16)
            var rng = new Random();
            int indexToCorrupt = rng.Next(16, ciphertext.Length);
            ciphertext[indexToCorrupt] ^= 0xFF;

            // 3. Decrypt - Must return null, NEVER throw or return partial data
            try
            {
                using var decrypted = LuxVault.DecryptToBytes(ciphertext, password);
                return decrypted == null;
            }
            catch (Exception ex)
            {
                _output.WriteLine($"LuxVault threw during fuzzing: {ex.Message}");
                return false;
            }
        }

        #endregion

        #region IPC Engine (Pipes & Queues) Robustness

        [Property(DisplayName = "ObjectQueue: Should maintain atomicity for fuzzed payloads")]
        public bool ObjectQueue_Atomicity_Fuzz_Property(byte[][] messages)
        {
            if (messages == null || messages.Length == 0) return true;

            var queue = new ObjectQueueNode("fuzz_queue");

            // 1. Write all messages
            foreach (var m in messages)
            {
                if (m == null) continue;
                queue.WriteAsync(m).Wait();
            }

            // 2. Read back and verify exact matches
            foreach (var original in messages)
            {
                if (original == null) continue;
                var readTask = queue.ReadAsync(1024 * 1024);
                readTask.Wait();
                var recovered = readTask.Result.ToArray();

                if (!original.SequenceEqual(recovered)) return false;
            }

            return true;
        }

        [Fact]
        public async Task DataPipe_Concurrent_Fragmentation_Stress()
        {
            var pipe = new DataPipeNode("stress_pipe");
            const int totalBytes = 1024 * 1024; // 1MB
            byte[] sourceData = new byte[totalBytes];
            RandomNumberGenerator.Fill(sourceData);

            // 1. Writer: Pushes data in random chunk sizes
            var writeTask = Task.Run(async () =>
            {
                int sent = 0;
                var rng = new Random();
                while (sent < totalBytes)
                {
                    int chunk = rng.Next(1, 8192);
                    int remaining = totalBytes - sent;
                    int actual = Math.Min(chunk, remaining);
                    await pipe.WriteAsync(sourceData.AsMemory(sent, actual));
                    sent += actual;
                }
            });

            // 2. Reader: Pulls data in random chunk sizes
            byte[] recoveredData = new byte[totalBytes];
            var readTask = Task.Run(async () =>
            {
                int received = 0;
                var rng = new Random();
                while (received < totalBytes)
                {
                    uint request = (uint)rng.Next(1, 4096);
                    var chunk = await pipe.ReadAsync(request);
                    chunk.ToArray().CopyTo(recoveredData, received);
                    received += chunk.Length;
                }
            });

            await Task.WhenAll(writeTask, readTask);
            recoveredData.Should().Equal(sourceData, "Data Pipe must reassemble fragmented stream perfectly");
        }

        #endregion

        #region PowerShell Isolation & Failure Paths

        [Fact]
        public async Task PowerShell_Process_Crash_Returns_Failure_Status()
        {
            var job = new PowerShellJob("crash-job");
            // Command that exits with non-zero
            job.Script = "[System.Environment]::Exit(1)";

            await job.RunAsync();

            job.Status.Should().Be("Failed");
            job.Errors.ToString().Should().Contain("exited with code: 1");
        }

        [Fact]
        public async Task PowerShell_Syntax_Error_Captured_In_Errors_File()
        {
            var job = new PowerShellJob("syntax-job");
            job.Script = "This Is Not Valid PowerShell !!! @@@";

            await job.RunAsync();

            job.Status.Should().Be("Failed");
            job.Errors.ToString().Should().NotBeEmpty();
        }

        #endregion

        #region SecureMemoryArena Boundary Testing

        [Fact]
        public async Task Arena_Exhaustion_Does_Not_Crash_Server()
        {
            // We use the sharded Arenas pool
            var arena = LuxVault.GetLocalArena();
            var allocations = new List<Memory<byte>>();

            try
            {
                // 1. Attempt to exhaust the 1MB arena shard
                // (Allocating 128 chunks of 10KB = 1.28MB)
                for (int i = 0; i < 150; i++)
                {
                    try { allocations.Add(arena.Allocate(10240).ToArray()); }
                    catch (Exception ex) when (ex is OutOfMemoryException || ex is InvalidOperationException)
                    {
                        // Expected failure when shard is full.
                    }
                }

                // 2. Verify we can still perform small allocations in OTHER shards
                // By switching threads, we hit a different shard.
                bool otherShardWorks = false;
                await Task.Run(() =>
                {
                    var otherArena = LuxVault.GetLocalArena();
                    var span = otherArena.Allocate(100);
                    otherShardWorks = span.Length == 100;
                    otherArena.Free(span);
                });

                otherShardWorks.Should().BeTrue("Exhausting one arena shard should not block other threads");
            }
            finally
            {
                // Cleanup
                foreach (var a in allocations) arena.Free(a.Span);
            }
        }

        #endregion
    }
}

using System;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using FluentAssertions;
using NinePSharp.Backends.PowerShell;
using NinePSharp.Messages;
using NinePSharp.Server.Utils;
using Xunit;

namespace NinePSharp.Tests
{
    public class GridSideEffectTests
    {
        [Fact]
        public async Task PowerShell_Job_Lifecycle_Ensures_SideEffect_Cleanup()
        {
            var fs = new PowerShellFileSystem();
            string jobId = $"cleanup-test-{Guid.NewGuid():N}";
            string marker = $"NINEPSHARP_CLEANUP_{Guid.NewGuid():N}";

            // 1. Create job
            var jobsFs = (PowerShellFileSystem)fs.Clone();
            await jobsFs.WalkAsync(new Twalk(1, 1, 2, new[] { "jobs" }));
            await jobsFs.MkdirAsync(new Tmkdir(0, 1, 2, jobId, 0755, 0));

            // 2. Start a script that outputs its own PID and then sleeps
            var scriptFs = (PowerShellFileSystem)jobsFs.Clone();
            await scriptFs.WalkAsync(new Twalk(1, 2, 3, new[] { jobId, "script.ps1" }));
            string script = $"Write-Output $pid; # {marker}{Environment.NewLine}Start-Sleep -Seconds 10";
            await scriptFs.WriteAsync(new Twrite(1, 3, 0, Encoding.UTF8.GetBytes(script)));

            // 3. Capture the PID from the output file
            int pid = 0;
            for (int attempt = 0; attempt < 20 && pid == 0; attempt++)
            {
                await Task.Delay(250);
                var outFs = (PowerShellFileSystem)jobsFs.Clone();
                await outFs.WalkAsync(new Twalk(1, 2, 4, new[] { jobId, "output.json" }));
                var readRes = await outFs.ReadAsync(new Tread(1, 4, 0, 4096));
                string output = Encoding.UTF8.GetString(readRes.Data.ToArray());
                var digits = new string(output.Where(char.IsDigit).ToArray());
                if (!string.IsNullOrEmpty(digits))
                {
                    int.TryParse(digits, out pid);
                }
            }
            pid.Should().BeGreaterThan(0, "PowerShell output should contain the job PID before cleanup assertions.");

            // ASSERT SIDE EFFECT: Process must exist in OS
            Process.GetProcessById(pid).Should().NotBeNull();

            // 4. KILL the job via Tremove
            var removeFs = (PowerShellFileSystem)jobsFs.Clone();
            await removeFs.WalkAsync(new Twalk(1, 2, 5, new[] { jobId }));
            await removeFs.RemoveAsync(new Tremove(1, 5));

            // 5. ASSERT SIDE EFFECT: Process must be GONE from OS immediately
            await Task.Delay(500); // Give OS a tiny window to reap
            Action act = () => Process.GetProcessById(pid);
            act.Should().Throw<ArgumentException>("Process must be terminated by the server when the job is removed.");

            // 6. ASSERT SIDE EFFECT: Temp files must be cleaned up
            var tempFiles = Directory.GetFiles(Path.GetTempPath(), $"*.ps1");
            bool leakedScriptFound = tempFiles.Any(f =>
            {
                try { return File.ReadAllText(f).Contains(marker, StringComparison.Ordinal); }
                catch { return false; }
            });
            leakedScriptFound.Should().BeFalse("Temporary script files must be deleted after job completion or removal.");
        }

        [Fact]
        public async Task LuxVault_Store_SideEffect_Is_Opaque()
        {
            const string secretName = "side-effect-secret";
            const string password = "opaque-pass";
            byte[] plaintext = Encoding.UTF8.GetBytes("sensitive-data-12345");

            using var ss = new System.Security.SecureString();
            foreach (var c in password) ss.AppendChar(c);
            ss.MakeReadOnly();

            // 1. Store the secret
            LuxVault.StoreSecret(secretName, plaintext, ss);

            // 2. Predict the path
            byte[] nameBytes = Encoding.UTF8.GetBytes(secretName);
            byte[] seed = new byte[32];
            LuxVault.DeriveSeed(password, nameBytes, seed);
            string hiddenId = LuxVault.GenerateHiddenId(seed);
            string path = LuxVault.GetVaultPath($"secret_{hiddenId}.vlt");

            // 3. ASSERT SIDE EFFECT: File exists and is NOT readable as cleartext
            File.Exists(path).Should().BeTrue();
            byte[] diskData = File.ReadAllBytes(path);
            Encoding.UTF8.GetString(diskData).Should().NotContain("sensitive-data-12345", "Vault file must be encrypted on disk.");

            // 4. Cleanup side effect
            File.Delete(path);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using Moq;
using NinePSharp.Messages;
using NinePSharp.Server.Backends.gRPC;
using NinePSharp.Server.Configuration.Models;
using NinePSharp.Server.Interfaces;
using NinePSharp.Server.Utils;
using Xunit;

namespace NinePSharp.Tests;

public class GrpcBackendTests
{
    private readonly Mock<ILuxVaultService> _vaultMock = new();
    private readonly Mock<IGrpcTransport> _transportMock = new();
    private readonly GrpcBackendConfig _config = new() { Host = "localhost", Port = 50051 };

    [Fact]
    public async Task Grpc_Method_Call_Works_And_Stores_Response()
    {
        // Arrange
        var responsePayload = new byte[] { 0x08, 0x01 }; // Protobuf: field 1, value 1
        _transportMock.Setup(x => x.CallAsync(It.IsAny<string>(), It.IsAny<string>(), It.IsAny<byte[]>(), It.IsAny<IDictionary<string, string>>()))
                      .ReturnsAsync(responsePayload);

        var fs = new GrpcFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Walk to /services/Greeter/SayHello
        await fs.WalkAsync(new Twalk(1, 0, 1, new[] { "services", "Greeter", "SayHello" }));

        // Act - Write Request
        var requestPayload = new byte[] { 0x0A, 0x05, 0x57, 0x6F, 0x72, 0x6C, 0x64 }; // Protobuf: field 1, length 5, "World"
        await fs.WriteAsync(new Twrite(1, 1, 0, requestPayload));

        // Act - Read Response
        var read = await fs.ReadAsync(new Tread(1, 1, 0, 8192));
        var result = read.Data.ToArray();

        // Assert
        Assert.True(responsePayload.SequenceEqual(result));
        _transportMock.Verify(x => x.CallAsync("Greeter", "SayHello", It.IsAny<byte[]>(), It.IsAny<IDictionary<string, string>>()), Times.Once);
    }

    [Fact]
    public async Task Grpc_Metadata_Is_Passed_To_Transport()
    {
        // Arrange
        IDictionary<string, string>? capturedMetadata = null;
        _transportMock.Setup(x => x.CallAsync(It.IsAny<string>(), It.IsAny<string>(), It.IsAny<byte[]>(), It.IsAny<IDictionary<string, string>>()))
                      .Callback<string, string, byte[], IDictionary<string, string>>((s, m, p, meta) => capturedMetadata = meta)
                      .ReturnsAsync(Array.Empty<byte>());

        var fs = new GrpcFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Walk to .metadata and write
        await fs.WalkAsync(new Twalk(1, 0, 1, new[] { ".metadata" }));
        await fs.WriteAsync(new Twrite(1, 1, 0, Encoding.UTF8.GetBytes("authorization: Bearer token123\ncustom-header: value")));

        // Walk to method
        var methodFs = fs.Clone();
        await methodFs.WalkAsync(new Twalk(1, 0, 2, new[] { "..", "services", "Greeter", "SayHello" }));

        // Act
        await methodFs.WriteAsync(new Twrite(1, 2, 0, Array.Empty<byte>()));

        // Assert
        Assert.NotNull(capturedMetadata);
        Assert.Equal("Bearer token123", capturedMetadata["authorization"]);
        Assert.Equal("value", capturedMetadata["custom-header"]);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using FsCheck;
using FsCheck.Xunit;
using Moq;
using NinePSharp.Messages;
using NinePSharp.Server.Backends.gRPC;
using NinePSharp.Server.Configuration.Models;
using NinePSharp.Server.Interfaces;
using Xunit;

namespace NinePSharp.Tests;

public class GrpcPropertyTests
{
    private readonly Mock<ILuxVaultService> _vaultMock = new();
    private readonly Mock<IGrpcTransport> _transportMock = new();
    private readonly GrpcBackendConfig _config = new() { Host = "localhost", Port = 50051 };

    [Property]
    public bool Metadata_Parsing_Is_Robust_Property(string input)
    {
        if (input == null) return true;

        var fs = new GrpcFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Walk to .metadata
        fs.WalkAsync(new Twalk(1, 0, 1, new[] { ".metadata" })).Wait();

        try
        {
            // Write randomized data to metadata
            var data = Encoding.UTF8.GetBytes(input);
            fs.WriteAsync(new Twrite(1, 1, 0, data)).Wait();

            // Read it back to ensure no crash and basic consistency
            var read = fs.ReadAsync(new Tread(1, 1, 0, 8192)).Result;
            return true;
        }
        catch (Exception)
        {
            // We only fail if the parser itself throws an unhandled exception
            return false;
        }
    }

    [Property]
    public bool Grpc_Clone_Isolation_Property(string key, string value)
    {
        if (string.IsNullOrWhiteSpace(key) || string.IsNullOrWhiteSpace(value)) return true;
        // Strip colon and newline from key/value as they are delimiters
        key = key.Replace(":", "").Replace("\n", "").Replace("\r", "").Trim();
        value = value.Replace("\n", "").Replace("\r", "").Trim();
        if (string.IsNullOrWhiteSpace(key) || string.IsNullOrWhiteSpace(value)) return true;

        var fs1 = new GrpcFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Set metadata in fs1
        fs1.WalkAsync(new Twalk(1, 0, 1, new[] { ".metadata" })).Wait();
        fs1.WriteAsync(new Twrite(1, 1, 0, Encoding.UTF8.GetBytes($"{key}: {value}"))).Wait();

        // Clone to fs2
        var fs2 = (GrpcFileSystem)fs1.Clone();

        // Mutate fs1 metadata
        fs1.WriteAsync(new Twrite(1, 1, 0, Encoding.UTF8.GetBytes($"{key}: mutated"))).Wait();

        // Read fs2 metadata - should remain the original value
        var read2 = fs2.ReadAsync(new Tread(1, 1, 0, 8192)).Result;
        var content2 = Encoding.UTF8.GetString(read2.Data.ToArray());

        return content2.Contains($"{key}: {value}") && !content2.Contains("mutated");
    }

    [Property]
    public bool Grpc_Path_Navigation_Stability_Property(string[] path)
    {
        if (path == null) return true;
        // Clean path segments to avoid nulls/empty
        var cleanPath = path.Where(p => p != null).ToArray();

        var fs = new GrpcFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        try
        {
            // Walk any randomized path
            var response = fs.WalkAsync(new Twalk(1, 0, 1, cleanPath)).Result;

            // Regardless of whether the path exists, it should return a valid Rwalk, never crash
            return response.Tag == 1;
        }
        catch (Exception)
        {
            return false;
        }
    }
}

using System;
using System.Text;
using NinePSharp.Constants;
using NinePSharp.Messages;
using NinePSharp.Protocol;
using Xunit;

namespace NinePSharp.Tests.Helpers;

public abstract class TestBase
{
    protected void RoundTripTest<T>(uint size, ushort tag, Func<ReadOnlySpan<byte>, T> deserializer, Action<T> assertFunc, Func<T> instantiator, Action<T, Span<byte>> serializer)
    {
        var original = instantiator();
        var buffer = new byte[size];
        serializer(original, buffer);

        var msgSize = System.Buffers.Binary.BinaryPrimitives.ReadUInt32LittleEndian(buffer.AsSpan()[..4]);
        Assert.Equal(size, msgSize);

        var msgTag = System.Buffers.Binary.BinaryPrimitives.ReadUInt16LittleEndian(buffer.AsSpan().Slice(5, 2));
        Assert.Equal(tag, msgTag);

        var deserialized = deserializer(buffer);
        assertFunc(deserialized);
    }
}

using System;
