        cfg.Endpoints.Add(new JsonRpcEndpointConfig { Name = "leaf", Path = "a/b/c/d/e", Method = "m" });
        var fs = new JsonRpcFileSystem(cfg, new FakeTransport());

        var result = await fs.WalkAsync(new Twalk(1, 10, 11, new[] { "a", "b", "c", "d", "e", "leaf" }));
