namespace NinePSharp.Tests;

public class MqttBackendTests
{
    private readonly Mock<ILuxVaultService> _vaultMock = new();
    private readonly Mock<IMqttTransport> _transportMock = new();
    private readonly MqttBackendConfig _config = new() { BrokerUrl = "localhost", ClientId = "test-client" };

    [Fact]
    public async Task Mqtt_Publish_Works()
    {
        // Arrange
        _transportMock.Setup(x => x.PublishAsync(It.IsAny<string>(), It.IsAny<byte[]>()))
                      .Returns(Task.CompletedTask);

        var fs = new MqttFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Walk to /topics/home/sensor
        await fs.WalkAsync(new Twalk(1, 0, 1, new[] { "topics", "home", "sensor" }));

        // Act - Write Payload
        var payload = Encoding.UTF8.GetBytes("22.5C");
        await fs.WriteAsync(new Twrite(1, 1, 0, payload));

        // Assert
        _transportMock.Verify(x => x.PublishAsync("home/sensor", It.IsAny<byte[]>()), Times.Once);
    }

    [Fact]
    public async Task Mqtt_Subscribe_And_Read_Works()
    {
        // Arrange
        var topic = "home/sensor";
        var message = Encoding.UTF8.GetBytes("incoming-data");

        _transportMock.Setup(x => x.SubscribeAsync(topic)).Returns(Task.CompletedTask);
        _transportMock.Setup(x => x.GetNextMessageAsync(topic)).ReturnsAsync(message);

        var fs = new MqttFileSystem(_config, _transportMock.Object, _vaultMock.Object);

        // Act - Walk (triggers subscribe)
        await fs.WalkAsync(new Twalk(1, 0, 1, new[] { "topics", "home", "sensor" }));

        // Act - Read
        var read = await fs.ReadAsync(new Tread(1, 1, 0, 8192));
        var result = Encoding.UTF8.GetString(read.Data.ToArray());

        // Assert
        Assert.Equal("incoming-data", result);
        _transportMock.Verify(x => x.SubscribeAsync(topic), Times.Once);
    }

    [Fact]
    public async Task Mqtt_Clone_Move_DoesNotAffect_OriginalPublishTopic()
    {
        _transportMock.Setup(x => x.SubscribeAsync(It.IsAny<string>())).Returns(Task.CompletedTask);
        _transportMock.Setup(x => x.PublishAsync(It.IsAny<string>(), It.IsAny<byte[]>())).Returns(Task.CompletedTask);

        var fs1 = new MqttFileSystem(_config, _transportMock.Object, _vaultMock.Object);
        await fs1.WalkAsync(new Twalk(1, 0, 1, new[] { "topics", "alpha" }));

        var fs2 = fs1.Clone();
        await fs2.WalkAsync(new Twalk(2, 1, 3, new[] { "..", "beta" }));

        await fs1.WriteAsync(new Twrite(3, 1, 0, new byte[] { 0x01 }));

        _transportMock.Verify(x => x.PublishAsync("alpha", It.IsAny<byte[]>()), Times.Once);
        _transportMock.Verify(x => x.PublishAsync("beta", It.IsAny<byte[]>()), Times.Never);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using FsCheck;
using FsCheck.Xunit;
using Moq;
using NinePSharp.Messages;
using NinePSharp.Constants;
using NinePSharp.Server.Backends.MQTT;
using NinePSharp.Server.Configuration.Models;
using NinePSharp.Server.Interfaces;
using Xunit;

namespace NinePSharp.Tests;

public class MqttPropertyTests
{
    private readonly MqttBackendConfig _config = new() { BrokerUrl = "localhost", ClientId = "property-test" };

    [Property]
    public bool Mqtt_Path_Navigation_Stability_Property(string[] path)
    {
        if (path == null) return true;
        var cleanPath = path.Where(p => p != null).ToArray();

        var vaultMock = new Mock<ILuxVaultService>();
        var transportMock = new Mock<IMqttTransport>();
        transportMock.Setup(x => x.SubscribeAsync(It.IsAny<string>())).Returns(Task.CompletedTask);
        var fs = new MqttFileSystem(_config, transportMock.Object, vaultMock.Object);

        try
        {
            // Walk any randomized path
            var response = fs.WalkAsync(new Twalk(1, 0, 1, cleanPath)).Result;

            // Should return valid response (struct), never crash
            return response.Tag == 1;
        }
        catch (Exception)
        {
            return false;
        }
    }

    [Property]
    public bool Mqtt_Topic_Mapping_Robustness_Property(string topicPart)
    {
        if (string.IsNullOrWhiteSpace(topicPart)) return true;
        // Strip null chars which are problematic for string mapping in some environments
        topicPart = topicPart.Replace("\0", "");
        if (string.IsNullOrWhiteSpace(topicPart)) return true;

        var vaultMock = new Mock<ILuxVaultService>();
        var transportMock = new Mock<IMqttTransport>();
        transportMock.Setup(x => x.SubscribeAsync(It.IsAny<string>())).Returns(Task.CompletedTask);
        transportMock.Setup(x => x.PublishAsync(It.IsAny<string>(), It.IsAny<byte[]>())).Returns(Task.CompletedTask);
        var fs = new MqttFileSystem(_config, transportMock.Object, vaultMock.Object);

        try
        {
            // Walk to topics/randomPart
            fs.WalkAsync(new Twalk(1, 0, 1, new[] { "topics", topicPart })).Wait();

            // Attempt a write (publish)
            var data = new byte[] { 1, 2, 3 };
            fs.WriteAsync(new Twrite(1, 1, 0, data)).Wait();

            // Verify the transport received the correctly formatted topic
            transportMock.Verify(x => x.PublishAsync(topicPart, It.IsAny<byte[]>()), Times.AtLeastOnce());
            return true;
        }
        catch (Exception)
        {
            // If the topic is invalid for MQTT (e.g. too long), the transport might throw, 
            // which the FS should handle or we accept as a "valid" failure.
            // We return true as long as it doesn't crash the server.
            return true;
        }
    }

    [Property]
    public bool Mqtt_Clone_Isolation_Property(string topic1, string topic2)
    {
        topic1 = topic1?.Replace("\0", "") ?? string.Empty;
        topic2 = topic2?.Replace("\0", "") ?? string.Empty;
        if (string.IsNullOrWhiteSpace(topic1) || string.IsNullOrWhiteSpace(topic2)) return true;
        if (topic1 == topic2) return true;

        var vaultMock = new Mock<ILuxVaultService>();
        var transportMock = new Mock<IMqttTransport>();
        transportMock.Setup(x => x.SubscribeAsync(It.IsAny<string>())).Returns(Task.CompletedTask);
        transportMock.Setup(x => x.PublishAsync(It.IsAny<string>(), It.IsAny<byte[]>())).Returns(Task.CompletedTask);
        var fs1 = new MqttFileSystem(_config, transportMock.Object, vaultMock.Object);

        // Walk fs1 to topic1
        fs1.WalkAsync(new Twalk(1, 0, 1, new[] { "topics", topic1 })).Wait();

        // Clone to fs2
        var fs2 = fs1.Clone();

        // Walk fs2 to topic2
        fs2.WalkAsync(new Twalk(1, 1, 2, new[] { "..", topic2 })).Wait();

        // Act - publish on fs1
        fs1.WriteAsync(new Twrite(1, 1, 0, new byte[] { 0 })).Wait();

        // Verify fs1 published to topic1, not topic2
        transportMock.Verify(x => x.PublishAsync(topic1, It.IsAny<byte[]>()), Times.Once());
        transportMock.Verify(x => x.PublishAsync(topic2, It.IsAny<byte[]>()), Times.Never());

        return true;
    }
}

using System;
using System.Linq;
using System.Text;
using FsCheck;
using FsCheck.Xunit;
using NinePSharp.Parser;
using NinePSharp.Generators;
using NinePSharp.Messages;
using NinePSharp.Constants;
using Xunit;

namespace NinePSharp.Tests;

/// <summary>
/// Targeted property tests to kill surviving mutants in low-coverage messages
/// </summary>
public class MutationKillerTests
{
    // ─── Stat Tests (54.29% coverage) ────────────────────────────────────

    [Property(Arbitrary = new[] { typeof(NinePSharp.Generators.Generators.NinePArb) }, MaxTest = 500)]
    public void Stat_Size_Calculation_Matches_Actual_Serialization(Stat stat)
    {
        // Verify that the Size field accurately reflects serialized size
        var buffer = new byte[stat.Size];
        int offset = 0;
        stat.WriteTo(buffer, ref offset);

        Assert.Equal(stat.Size, (uint)offset);
    }

    [Property(Arbitrary = new[] { typeof(NinePSharp.Generators.Generators.NinePArb) }, MaxTest = 500)]
    public void Stat_DotU_Extension_Fields_Only_Present_When_DotU_True(Stat stat)
    {
        // Verify 9P2000.u extension logic
        if (stat.DotU)
        {
            Assert.NotNull(stat.NUid);
            Assert.NotNull(stat.NGid);
            Assert.NotNull(stat.NMuid);
        }
        else
        {
            // When DotU is false, extension fields may be null
            // But if present, they shouldn't affect serialization
        }
    }

    [Property(Arbitrary = new[] { typeof(NinePSharp.Generators.Generators.NinePArb) }, MaxTest = 300)]
    public void Stat_Variable_Length_Strings_Roundtrip_Correctly(Stat stat)
    {
        var buffer = new byte[stat.Size];
        int writeOffset = 0;
        stat.WriteTo(buffer, ref writeOffset);

        int readOffset = 0;
        var parsed = new Stat(buffer, ref readOffset, stat.DotU);

        // 9P protocol contract: null and empty string are equivalent (both serialize to 0x00 0x00)
        Assert.Equal(stat.Name ?? "", parsed.Name);
        Assert.Equal(stat.Uid ?? "", parsed.Uid);
        Assert.Equal(stat.Gid ?? "", parsed.Gid);
        Assert.Equal(stat.Muid ?? "", parsed.Muid);

        if (stat.DotU)
        {
            Assert.Equal(stat.Extension ?? "", parsed.Extension ?? "");
        }
    }

    [Property(MaxTest = 200)]
    public void Stat_CalculateSize_Method_Handles_Edge_Cases(string name, string uid, string gid, string muid, bool dotu)
    {
        if (name == null) name = "";
        if (uid == null) uid = "";
        if (gid == null) gid = "";
        if (muid == null) muid = "";

        // Should never throw, even with extreme inputs
        var size = Stat.CalculateSize(name, uid, gid, muid, dotu, dotu ? "ext" : null);

        // Minimum size: 2 (size field) + 39 (fixed fields) + 8 (4 empty strings) = 49
        Assert.True(size >= 49, $"Size too small: {size}");

        // Size should account for all string bytes
        int expectedStringBytes =
            2 + Encoding.UTF8.GetByteCount(name) +
            2 + Encoding.UTF8.GetByteCount(uid) +
            2 + Encoding.UTF8.GetByteCount(gid) +
