using System;
using FsCheck;
using FsCheck.Xunit;
using NinePSharp.Parser;
using Xunit;

namespace NinePSharp.Tests;

public class ParserPropertyTests
{
    [Property]
    public bool Parser_Never_Crashes_On_Random_Bytes(byte[] data)
    {
        if (data == null) return true;

        try
        {
            // Fuzzing logic: feed random bytes to the parser
            // We expect Ok or Error, but NO Exceptions.
            var result = NinePParser.parse(false, data.AsMemory());

            // If it returns Ok, the data happened to be a valid message.
            // If it returns Error, it handled the malformed data correctly.
            // The property holds true in both cases.
            return true;
        }
        catch (Exception ex)
        {
            // If we catch an exception, the parser failed to handle the input gracefully.
            Console.WriteLine($"Parser crashed with: {ex}");
            return false;
        }
    }

    [Property]
    public bool Parser_9u_Never_Crashes_On_Random_Bytes(byte[] data)
    {
        if (data == null) return true;

        try
        {
            var result = NinePParser.parse(true, data.AsMemory());
            return true;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Parser (9u) crashed with: {ex}");
            return false;
        }
    }
}

using System;
using System.Linq;
using NinePSharp.Parser;
using NinePSharp.Generators;
using Xunit;

namespace NinePSharp.Tests;

public class ParserRobustnessTests
{
    [Fact]
    public void Parser_Handles_Partial_Messages_Gracefully()
    {
        var twalk = new NinePSharp.Messages.Twalk(1, 1, 2, new[] { "home", "user" });
        var fullBytes = new byte[twalk.Size];
        twalk.WriteTo(fullBytes);

        for (int i = 1; i < fullBytes.Length; i++)
        {
            var partial = fullBytes.AsMemory(0, i);
            var result = NinePParser.parse(true, partial);

            // Should return Error (too short), never crash
            Assert.True(result.IsError, $"Parser should return Error for length {i}, but was {result}");
        }
    }

    [Fact]
    public void Parser_Handles_Zero_Length_Buffer()
    {
        var result = NinePParser.parse(true, Memory<byte>.Empty);
        Assert.True(result.IsError);
    }

    [Theory]
    [InlineData(0)]
    [InlineData(1)]
    [InlineData(6)] // Just before type byte
    public void Parser_Handles_Too_Small_Header(int length)
    {
        var buffer = new byte[length];
        var result = NinePParser.parse(true, buffer.AsMemory());
        Assert.True(result.IsError);
    }

    [Fact]
    public void Parser_Rejects_Message_Size_Smaller_Than_Header()
    {
        var buffer = new byte[7];
        System.Buffers.Binary.BinaryPrimitives.WriteUInt32LittleEndian(buffer, 6); // Invalid size < 7
        buffer[4] = (byte)Constants.MessageTypes.Tversion;

        var result = NinePParser.parse(true, buffer.AsMemory());
        Assert.True(result.IsError);
    }

    [Fact]
    public void Parser_Fuzzing_Large_Buffer_With_Random_Garbage()
    {
        var rnd = new Random(42);
        var buffer = new byte[1024 * 1024]; // 1MB
        rnd.NextBytes(buffer);

        // Try parsing at various offsets
        for (int i = 0; i < 1000; i++)
        {
            int offset = rnd.Next(0, buffer.Length - 100);
            int len = rnd.Next(1, 100);

            // Should not crash
            NinePParser.parse(true, buffer.AsMemory(offset, len));
        }
    }
}

using System;
using System.Linq;
using System.Security;
using System.Security.Cryptography;
using System.Text;
using NinePSharp.Server.Configuration;
using NinePSharp.Server.Utils;
using Xunit;

namespace NinePSharp.Tests
{
    public class ProtectedSecretTests
    {
        private static SecureString ToSecureString(string value)
        {
            var secure = new SecureString();
            foreach (char c in value)
            {
                secure.AppendChar(c);
            }
            secure.MakeReadOnly();
            return secure;
        }

        public ProtectedSecretTests()
        {
            // Initialize session key if not already done by another test
            byte[] key = new byte[32];
            RandomNumberGenerator.Fill(key);
            ProtectedSecret.InitializeSessionKey(key);
        }

        [Fact]
        public void ProtectedSecret_RoundTrip_Works()
        {
            string original = "my-ultra-secret-password-123";
            using var originalSecure = ToSecureString(original);
            using var secret = new ProtectedSecret(originalSecure);

            // Should not show cleartext in ToString
            Assert.DoesNotContain(original, secret.ToString());
            Assert.Equal("********", secret.ToString());

            string? revealed = null;
            secret.Use(bytes => revealed = Encoding.UTF8.GetString(bytes));
            Assert.Equal(original, revealed);
        }

        [Fact]
        public void ProtectedSecret_EncryptionIsUniquePerInstance()
        {
            // This tests that even for the same plaintext, the encrypted data in memory is different
            // due to the random salt/nonce used by LuxVault internally.
            string plaintext = "static-secret";
            using var plaintextSecure1 = ToSecureString(plaintext);
            using var plaintextSecure2 = ToSecureString(plaintext);

            using var s1 = new ProtectedSecret(plaintextSecure1);
            using var s2 = new ProtectedSecret(plaintextSecure2);

            // We can't directly access _encryptedData as it is private, 
            // but we've verified LuxVault.Encrypt uses random nonces.
        }

        [Fact]
        public void ProtectedSecret_SecureString_RoundTrip_Works()
        {
            string original = "my-secure-password";
            using var ss = new SecureString();
            foreach (char c in original) ss.AppendChar(c);
            ss.MakeReadOnly();

            using var secret = new ProtectedSecret(ss);

            string recovered = "";
            secret.Use(bytes => {
                recovered = Encoding.UTF8.GetString(bytes);
            });

            Assert.Equal(original, recovered);
        }

        [Fact]
        public void ProtectedSecret_ReadOnlySpan_Constructor_Works()
        {
            byte[] original = { 0xDE, 0xAD, 0xBE, 0xEF };
            using var secret = new ProtectedSecret((ReadOnlySpan<byte>)original);

            byte[]? recovered = null;
            secret.Use(bytes => {
                recovered = bytes.ToArray();
            });

            Assert.NotNull(recovered);
            Assert.True(original.SequenceEqual(recovered!));
        }

        [Fact]
        public void ProtectedSecret_Use_DecodesCorrectly()
        {
            string original = "use-test-data";
            using var originalSecure = ToSecureString(original);
            using var secret = new ProtectedSecret(originalSecure);

            secret.Use(bytes => {
                Assert.Equal(original, Encoding.UTF8.GetString(bytes));
            });
        }

        [Fact]
        public void ProtectedSecret_DisposeClearsData()
        {
            using var secure = ToSecureString("data");
            var secret = new ProtectedSecret(secure);
            secret.Dispose();

            bool executed = false;
            Assert.Throws<ObjectDisposedException>(() => secret.Use(_ => executed = true));
            Assert.False(executed);
        }

        [Fact]
        public void ProtectedSecret_Initialization_FailsIfAlreadySet()
        {
            byte[] secondKey = new byte[32];
            RandomNumberGenerator.Fill(secondKey);

            // This shouldn't throw but should be a no-op (verified by code)
            ProtectedSecret.InitializeSessionKey(secondKey);

            // The original key (from constructor) should still be in effect
        }
    }
}

using System;
