using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Security;
using System.Text;
using System.Threading.Tasks;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging.Abstractions;
using NinePSharp.Messages;
using NinePSharp.Server.Backends;
using NinePSharp.Server.Configuration;
using NinePSharp.Server.Interfaces;
using NinePSharp.Server.Utils;
using Xunit;

namespace NinePSharp.Tests;

[Collection("Sequential Secret Tests")]
public class SecretBackendRegressionTests
{
    static SecretBackendRegressionTests()
    {
        byte[] sessionKey = new byte[32];
        for (int i = 0; i < sessionKey.Length; i++)
        {
            sessionKey[i] = (byte)i;
        }

        LuxVault.InitializeSessionKey(sessionKey);
        ProtectedSecret.InitializeSessionKey(sessionKey);
    }

    [Fact]
    public async Task Unlock_State_Persists_Across_New_FileSystem_Instances()
    {
        var backend = await CreateBackendAsync();
        string secretName = $"reg-unlock-{Guid.NewGuid():N}";
        const string password = "testpass";
        string expected = $"hidden-data-{Guid.NewGuid():N}";

        await ProvisionAsync(backend, password, secretName, expected);
        await UnlockAsync(backend, password, secretName);

        string readBack = await ReadSecretAsync(backend, secretName);
        Assert.Equal(expected, readBack);
    }

    [Fact]
    public async Task GetFileSystem_Returns_PathIsolated_Clone_Per_Connection()
    {
        var backend = await CreateBackendAsync();
        string secretName = $"reg-path-{Guid.NewGuid():N}";
        const string password = "testpass";
        const string expected = "hidden-data";

        await ProvisionAsync(backend, password, secretName, expected);
        await UnlockAsync(backend, password, secretName);

        var fsA = backend.GetFileSystem();
        await WalkToAsync(fsA, "vault", secretName);

        var fsB = backend.GetFileSystem();
        var rootRead = await fsB.ReadAsync(new Tread(1, 1, 0, 8192));
        var rootStats = ParseDirectory(rootRead.Data.ToArray());
        var names = rootStats.Select(s => s.Name).ToHashSet(StringComparer.Ordinal);

        Assert.Contains("provision", names);
        Assert.Contains("unlock", names);
        Assert.Contains("vault", names);
    }

    [Fact]
    public async Task Read_Uses_PhysicalVault_Stream_And_Sees_Updated_Secret_After_Unlock()
    {
        var backend = await CreateBackendAsync();
        string secretName = $"reg-stream-{Guid.NewGuid():N}";
        const string password = "testpass";
        const string valueV1 = "hidden-data-v1";
        const string valueV2 = "hidden-data-v2";

        await ProvisionAsync(backend, password, secretName, valueV1);
        await UnlockAsync(backend, password, secretName);

        string firstRead = await ReadSecretAsync(backend, secretName);
        Assert.Equal(valueV1, firstRead);

        // Overwrite the same physical vault entry after unlock.
        await ProvisionAsync(backend, password, secretName, valueV2);

        string secondRead = await ReadSecretAsync(backend, secretName);
        Assert.Equal(valueV2, secondRead);
    }

    [Fact]
    public void StoreSecret_Uses_AppContext_BaseDirectory_Not_CurrentDirectory()
    {
        string secretName = $"reg-cwd-{Guid.NewGuid():N}";
        const string password = "cwd-password";
        byte[] payload = Encoding.UTF8.GetBytes("cwd-data");

        byte[] nameBytes = Encoding.UTF8.GetBytes(secretName);
        byte[] seed = new byte[32];
        LuxVault.DeriveSeed(password, nameBytes, seed);
        string hiddenId = LuxVault.GenerateHiddenId(seed);
        string expectedPath = LuxVault.GetVaultPath($"secret_{hiddenId}.vlt");

        string tempCwd = Path.Combine(Path.GetTempPath(), $"ninepsharp-reg-{Guid.NewGuid():N}");
        Directory.CreateDirectory(tempCwd);
        string originalCwd = Directory.GetCurrentDirectory();
        string cwdRelativePath = Path.Combine(tempCwd, $"secret_{hiddenId}.vlt");

        using var securePassword = ToSecureString(password);
        try
        {
            Directory.SetCurrentDirectory(tempCwd);
            LuxVault.StoreSecret(secretName, payload, securePassword);
        }
        finally
        {
            Directory.SetCurrentDirectory(originalCwd);
            Array.Clear(payload, 0, payload.Length);
            Array.Clear(nameBytes, 0, nameBytes.Length);
            Array.Clear(seed, 0, seed.Length);

            if (Directory.Exists(tempCwd))
            {
                Directory.Delete(tempCwd, recursive: true);
            }
        }

        Assert.True(File.Exists(expectedPath));
        Assert.False(File.Exists(cwdRelativePath));
    }

    private static async Task<SecretBackend> CreateBackendAsync()
    {
        var backend = new SecretBackend(new LuxVaultService(), NullLoggerFactory.Instance);
        IConfiguration config = new ConfigurationBuilder()
            .AddInMemoryCollection(new Dictionary<string, string?>())
            .Build();
        await backend.InitializeAsync(config);
        return backend;
    }

    private static async Task ProvisionAsync(SecretBackend backend, string password, string name, string value)
    {
        var fs = backend.GetFileSystem();
        await WalkToAsync(fs, "provision");

        byte[] data = Encoding.UTF8.GetBytes($"{password}:{name}:{value}");
        try
        {
            var write = await fs.WriteAsync(new Twrite(1, 1, 0, data));
            Assert.Equal((uint)data.Length, write.Count);
        }
        finally
        {
            Array.Clear(data);
        }
    }

    private static async Task UnlockAsync(SecretBackend backend, string password, string name)
    {
        var fs = backend.GetFileSystem();
        await WalkToAsync(fs, "unlock");

        byte[] data = Encoding.UTF8.GetBytes($"{password}:{name}");
        try
        {
            var write = await fs.WriteAsync(new Twrite(1, 1, 0, data));
            Assert.Equal((uint)data.Length, write.Count);
        }
        finally
        {
            Array.Clear(data);
        }
    }

    private static async Task<string> ReadSecretAsync(SecretBackend backend, string name)
    {
        var fs = backend.GetFileSystem();
        await WalkToAsync(fs, "vault", name);

        var read = await fs.ReadAsync(new Tread(1, 1, 0, 8192));
        return Encoding.UTF8.GetString(read.Data.Span);
    }

    private static async Task WalkToAsync(INinePFileSystem fs, params string[] path)
    {
        var walk = await fs.WalkAsync(new Twalk(1, 1, 2, path));
        Assert.NotNull(walk.Wqid);
        Assert.Equal(path.Length, walk.Wqid.Length);
    }

    private static List<Stat> ParseDirectory(byte[] data)
    {
        var stats = new List<Stat>();
        int offset = 0;
        while (offset < data.Length)
        {
            stats.Add(new Stat(data, ref offset));
        }

        return stats;
    }

    private static SecureString ToSecureString(string value)
    {
        var secure = new SecureString();
        foreach (char c in value)
        {
            secure.AppendChar(c);
        }

        secure.MakeReadOnly();
        return secure;
    }
}

using FsCheck;
using FsCheck.Xunit;
using Microsoft.Extensions.Logging.Abstractions;
using NinePSharp.Messages;
using NinePSharp.Protocol;
using NinePSharp.Server.Backends;
using NinePSharp.Server.Configuration.Models;
using NinePSharp.Server.Interfaces;
using NinePSharp.Server.Utils;
using System;
using System.Threading.Tasks;
using Xunit;
using FluentAssertions;

namespace NinePSharp.Tests;

public class SecretFileSystemPropertyTests
{
    public SecretFileSystemPropertyTests()
    {
        SecretFileSystem.ClearSessionPasswords();
    }

    private static readonly ILuxVaultService _vault = new LuxVaultService();
    private static readonly SecretBackendConfig _config = new SecretBackendConfig();

    [Property(MaxTest = 30)]
    public void SecretFileSystem_StatfsAsync_BSize_Is_Constant(bool walkToVault)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        if (walkToVault)
        {
            fs.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();
        }

        var statfs = fs.StatfsAsync(new Tstatfs(100, walkToVault ? (ushort)2 : (ushort)1, walkToVault ? (ushort)2 : (ushort)1)).Result;

        // BSize should always be 4096
        statfs.BSize.Should().Be(4096);
    }

    [Property(MaxTest = 30)]
    public void SecretFileSystem_StatfsAsync_FsType_Is_Constant(bool walkToVault)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        if (walkToVault)
        {
            fs.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();
        }

        var statfs = fs.StatfsAsync(new Tstatfs(100, walkToVault ? (ushort)2 : (ushort)1, walkToVault ? (ushort)2 : (ushort)1)).Result;

        // FsType should always be the 9P magic number
        statfs.FsType.Should().Be(0x01021997);
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_Clone_Preserves_Path_Independence(bool walkInOriginal)
    {
        var fs1 = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        if (walkInOriginal)
        {
            fs1.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();
        }

        // Clone
        var fs2 = (SecretFileSystem)fs1.Clone();

        // Walk in clone
        fs2.WalkAsync(new Twalk(1, 1, 3, new[] { "provision" })).Wait();

        // Original should still be able to stat at its current path
        var statfs1 = fs1.StatfsAsync(new Tstatfs(100, walkInOriginal ? (ushort)2 : (ushort)1, walkInOriginal ? (ushort)2 : (ushort)1)).Result;

        // Should succeed without throwing
        statfs1.BSize.Should().Be(4096);
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_ReaddirAsync_Offset_Returns_LessOrEqual_Data(ushort offset)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);
        var safeOffset = (ulong)(offset % 1000);

        // Read all
        var resultAll = fs.ReaddirAsync(new Treaddir(100, 1, 1, 0, 8192)).Result;

        // Read with offset
        var resultWithOffset = fs.ReaddirAsync(new Treaddir(100, 1, 1, safeOffset, 8192)).Result;

        // With offset should return less or equal data
        resultWithOffset.Count.Should().BeLessThanOrEqualTo(resultAll.Count);
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_ReaddirAsync_Count_Limit_Is_Respected(PositiveInt countLimit)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);
        var limit = Math.Min((uint)countLimit.Get, 8192);

        var result = fs.ReaddirAsync(new Treaddir(100, 1, 1, 0, limit)).Result;

        // Result count should not exceed limit
        result.Count.Should().BeLessThanOrEqualTo(limit);
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_StatfsAsync_At_Root_Has_Fixed_File_Count()
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        var statfs = fs.StatfsAsync(new Tstatfs(100, 1, 1)).Result;

        // Root should always have 4 files (provision, unlock, vault + root itself)
        statfs.Files.Should().Be(4);
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_Walk_To_Vault_And_Back_Is_Consistent()
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        // Get statfs at root
        var statfsRoot1 = fs.StatfsAsync(new Tstatfs(100, 1, 1)).Result;

        // Walk to vault
        fs.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();

        // Walk back to root
        fs.WalkAsync(new Twalk(2, 2, 3, new[] { ".." })).Wait();

        // Get statfs at root again
        var statfsRoot2 = fs.StatfsAsync(new Tstatfs(100, 3, 3)).Result;

        // Should be same
        (statfsRoot1.Files == statfsRoot2.Files &&
         statfsRoot1.BSize == statfsRoot2.BSize &&
         statfsRoot1.FsType == statfsRoot2.FsType).Should().BeTrue();
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_Multiple_Clones_Are_Independent(PositiveInt cloneCount)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);
        var count = Math.Min(cloneCount.Get, 5);

        // Create multiple clones and walk them to different places
        for (int i = 0; i < count; i++)
        {
            var clone = (SecretFileSystem)fs.Clone();
            if (i % 2 == 0)
            {
                clone.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();
            }
        }

        // Original should still be at root
        var statfs = fs.StatfsAsync(new Tstatfs(100, 1, 1)).Result;

        statfs.Files.Should().Be(4); // Still at root
    }

    [Property(MaxTest = 20)]
    public void SecretFileSystem_ReaddirAsync_Returns_Valid_Count(bool atVault)
    {
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);

        if (atVault)
        {
            fs.WalkAsync(new Twalk(1, 1, 2, new[] { "vault" })).Wait();
        }

        var result = fs.ReaddirAsync(new Treaddir(100, atVault ? (ushort)2 : (ushort)1, atVault ? (ushort)2 : (ushort)1, 0, 8192)).Result;

        // Count should match data length
        result.Count.Should().Be((uint)result.Data.Length);
    }

    [Fact]
    public async Task SecretFileSystem_Property_Tests_Can_Run_Synchronously()
    {
        // Smoke test
        var fs = new SecretFileSystem(NullLogger.Instance, _config, _vault);
        var statfs = await fs.StatfsAsync(new Tstatfs(100, 1, 1));
        statfs.Files.Should().Be(4); // provision, unlock, vault + root
    }
}

